+    let parent = zvvcc_git_capture(&["rev-parse", "HEAD"], repo_dir)?;
+
+    let new_sha = zvvcc_git_capture(
+        &["commit-tree", &tree, "-p", &parent, "-m", message],
+        repo_dir,
+    )?;
+
+    zvvcc_git_capture(&["update-ref", "HEAD", &new_sha, &parent], repo_dir)?;
+
+    Ok(new_sha)
+}
